const header=document.getElementById("header");header&&window.addEventListener("scroll",()=>{header.classList.toggle("scrolled",window.scrollY>60)},{passive:!0});const trigger=document.getElementById("menuTrigger"),mobile=document.getElementById("mobileMenu"),overlay=document.getElementById("mobileOverlay");if(trigger&&mobile&&overlay){const e=()=>{trigger.classList.toggle("open"),mobile.classList.toggle("open"),overlay.classList.toggle("open"),document.body.style.overflow=mobile.classList.contains("open")?"hidden":""};trigger.addEventListener("click",e),overlay.addEventListener("click",e),mobile.querySelectorAll("a").forEach(t=>t.addEventListener("click",()=>{mobile.classList.contains("open")&&e()}))}document.querySelectorAll(".faq-item").forEach(e=>{const t=e.querySelector(".faq-q");t&&t.addEventListener("click",()=>{const t=e.classList.contains("open");e.parentElement.querySelectorAll(".faq-item").forEach(e=>e.classList.remove("open")),t||e.classList.add("open")})});